1	//! Static process and privilege tables, plus the boot-image table that
2	//! drives initial population.
3	//!
4	//! Storage uses `UnsafeCell<[T; N]>` wrapped in a `Sync` newtype: slice 2.2
5	//! runs on one CPU with interrupts masked, so a `Mutex` would buy nothing
6	//! over `unsafe` accessors that document the single-threaded invariant.
7	//! Slice 2.4 (timer + preemption) will revisit this — at that point we'll
8	//! need a per-table lock or a percpu pattern, not before.
9	
10	use core::cell::UnsafeCell;
11	
12	use minix4_kernel_shared::callnr::NR_KERN_CALLS_PHASE2;
13	use minix4_kernel_shared::com::{
14	    ASYNCM, CLOCK, DS_PROC_NR, HARDWARE, IDLE, INIT_PROC_NR, MEM_PROC_NR, MFS_PROC_NR,
15	    NR_BOOT_PROCS, NR_PROCS, NR_SYS_PROCS, NR_TASKS, PFS_PROC_NR, PM_PROC_NR, RS_PROC_NR,
16	    SCHED_PROC_NR, SYSTEM, TTY_PROC_NR, VFS_PROC_NR, VM_PROC_NR, boot_endpoint,
17	};
18	use minix4_kernel_shared::{PrivId, ProcNr};
19	
20	use super::flags::{
21	    BILLABLE, CSK_T, PREEMPTIBLE, ROOT_SYS_PROC, RTS_NO_PRIV, SRV_T, SYS_PROC, TSK_T,
22	    VM_SYS_PROC,
23	};
24	use super::priv_struct::{IPC_MAP_CHUNKS, K_CALL_MASK_CHUNKS, Priv};
25	use super::proc_struct::{PROC_NAME_LEN, Proc};
26	
