mod clock;
#[cfg(target_os = "none")]
mod ipc;
#[cfg(target_os = "none")]
mod mm;
#[cfg(target_os = "none")]
mod panic;
#[cfg(target_os = "none")]
mod proc;
#[cfg(target_os = "none")]
mod system;
#[cfg(target_os = "none")]
mod uart;

#[cfg(target_os = "none")]
use core::fmt::Write;

/// Scheduler tick rate (Hz). 100 Hz → 10 ms ticks, matching the classic
/// MINIX 3 cadence. Combined with the per-stub `quantum_ms = 5`, each task
/// gets ~50 ms of CPU before preemption.
#[cfg(target_os = "none")]
const TICK_HZ: u64 = 100;

#[cfg(target_os = "none")]
#[unsafe(no_mangle)]
extern "C" fn kmain() -> ! {
